'use client';

import React from 'react';
import { Star, ArrowDownToLine, Trash2 } from 'lucide-react';
import { useAdminMenuSettings } from '../../context/AdminMenuSettingsContext';
import { Button } from '@/shared/ui/primitives.public';
import { FormSection, FormField, SearchInput } from '@/shared/ui/forms-and-actions.public';
import { SectionHeader } from '@/shared/ui/navigation-and-layout.public';
import { cn } from '@/shared/utils/ui-utils';
import type { AdminNavLeaf } from '@/shared/contracts/admin';

function FavoriteItemActions({
  id,
  index,
  isLast,
  onMove,
  onToggle,
}: {
  id: string;
  index: number;
  isLast: boolean;
  onMove: (id: string, direction: 'up' | 'down') => void;
  onToggle: (id: string, checked: boolean) => void;
}): React.JSX.Element {
  return (
    <div className='flex items-center gap-1'>
      <Button
        type='button'
        variant='outline'
        size='sm'
        className='h-7 w-7 p-0'
        onClick={() => onMove(id, 'up')}
        disabled={index === 0}
        aria-label='Move favorite up'
        title='Move up'
      >
        <ArrowDownToLine className='size-3 rotate-180' />
      </Button>
      <Button
        type='button'
        variant='outline'
        size='sm'
        className='h-7 w-7 p-0'
        onClick={() => onMove(id, 'down')}
        disabled={isLast}
        aria-label='Move favorite down'
        title='Move down'
      >
        <ArrowDownToLine className='size-3' />
      </Button>
      <Button
        type='button'
        variant='ghost'
        size='sm'
        className='h-7 w-7 p-0 text-red-400 hover:bg-red-400/10 hover:text-red-300'
        onClick={() => onToggle(id, false)}
        aria-label='Remove from favorites'
        title='Remove'
      >
        <Trash2 className='size-3' />
      </Button>
    </div>
  );
}

function FavoriteItem({
  entry,
  index,
  isLast,
  onMove,
  onToggle,
}: {
  entry: AdminNavLeaf;
  index: number;
  isLast: boolean;
  onMove: (id: string, direction: 'up' | 'down') => void;
  onToggle: (id: string, checked: boolean) => void;
}): React.JSX.Element {
  const { id, label, parents } = entry;
  return (
    <div className='flex items-center justify-between gap-3 rounded-md border border-border/40 bg-gray-900/40 p-3'>
      <SectionHeader
        title={label}
        subtitle={parents.length > 0 ? parents.join(' / ') : undefined}
        size='xs'
        className='flex-1'
        actions={
          <FavoriteItemActions
            id={id}
            index={index}
            isLast={isLast}
            onMove={onMove}
            onToggle={onToggle}
          />
        }
      />
    </div>
  );
}

function FilteredItem({
  item,
  favoritesSet,
  handleToggleFavorite,
}: {
  item: AdminNavLeaf;
  favoritesSet: Set<string>;
  handleToggleFavorite: (id: string, checked: boolean) => void;
}): React.JSX.Element {
  const isFavorite = favoritesSet.has(item.id);
  const hrefLabel =
    item.href !== undefined && item.href !== null && item.href !== '' ? (
      <div className='truncate text-[11px] text-gray-600'>{item.href}</div>
    ) : null;

  return (
    <label
      key={item.id}
      className={cn(
        'flex cursor-pointer items-start gap-3 rounded-md border border-border/60 bg-card/30 px-3 py-2 transition hover:bg-card/50',
        isFavorite && 'border-amber-500/40 bg-amber-500/5'
      )}
    >
      <div className='mt-0.5 pt-0.5'>
        <Star
          className={cn(
            'size-3.5 transition-colors',
            isFavorite ? 'fill-amber-400 text-amber-400' : 'text-gray-600'
          )}
        />
      </div>
      <div className='min-w-0 flex-1'>
        <div className='flex items-center gap-2'>
          <span className='truncate text-xs font-medium text-gray-200'>{item.label}</span>
        </div>
        {hrefLabel}
      </div>
      <div className='flex h-5 items-center'>
        <input
          type='checkbox'
          className='size-3.5 rounded border-gray-600 bg-gray-800 text-amber-500 focus:ring-amber-500/40'
          checked={isFavorite}
          onChange={(e) => handleToggleFavorite(item.id, e.target.checked)}
          aria-label={`Favorite ${item.label}`}
        />
      </div>
    </label>
  );
}

function AddFavoriteSection({
  query,
  setQuery,
  filteredItems,
  favoritesSet,
  handleToggleFavorite,
}: {
  query: string;
  setQuery: (q: string) => void;
  filteredItems: AdminNavLeaf[];
  favoritesSet: Set<string>;
  handleToggleFavorite: (id: string, checked: boolean) => void;
}): React.JSX.Element {
  return (
    <div className='pt-2'>
      <FormField label='Add favorite'>
        <SearchInput
          value={query}
          onChange={(e: React.ChangeEvent<HTMLInputElement>) => setQuery(e.target.value)}
          onClear={() => setQuery('')}
          placeholder='Search menu items…'
          className='h-9 bg-gray-900/40'
          size='sm'
        />
      </FormField>
      <div className='mt-3 max-h-72 space-y-2 overflow-auto pr-2'>
        {filteredItems.map((item: AdminNavLeaf) => (
          <FilteredItem
            key={item.id}
            item={item}
            favoritesSet={favoritesSet}
            handleToggleFavorite={handleToggleFavorite}
          />
        ))}
      </div>
    </div>
  );
}

export function FavoritesSection(): React.JSX.Element {
  const {
    favoritesList,
    favoritesSet,
    query,
    setQuery,
    filteredItems,
    handleToggleFavorite,
    moveFavorite,
  } = useAdminMenuSettings();

  return (
    <FormSection
      title='Favorites'
      description='Pin menu items to appear at the top.'
      actions={<Star className='size-4 text-amber-300' />}
      className='p-6'
      variant='subtle'
    >
      <div className='space-y-3'>
        {favoritesList.length === 0 ? (
          <div className='rounded-md border border-border/40 bg-gray-900/20 p-3 text-xs text-gray-400'>
            No favorites yet. Select items below to pin them here.
          </div>
        ) : (
          <div className='space-y-2'>
            {favoritesList.map((entry: AdminNavLeaf | undefined, index: number) => {
              if (entry === undefined || entry === null) return null;
              return (
                <FavoriteItem
                  key={entry.id}
                  entry={entry}
                  index={index}
                  isLast={index === favoritesList.length - 1}
                  onMove={moveFavorite}
                  onToggle={handleToggleFavorite}
                />
              );
            })}
          </div>
        )}

        <AddFavoriteSection
          query={query}
          setQuery={setQuery}
          filteredItems={filteredItems}
          favoritesSet={favoritesSet}
          handleToggleFavorite={handleToggleFavorite}
        />
      </div>
    </FormSection>
  );
}

'use client';

import React, { useCallback, useMemo, useRef, useEffect } from 'react';
import {
  Plus,
  FolderPlus,
  Link2,
  Trash2,
  ArrowDownToLine,
} from 'lucide-react';
import { useAdminMenuSettings } from '../../context/AdminMenuSettingsContext';
import { Button } from '@/shared/ui/primitives.public';
import { FormSection, ToggleRow } from '@/shared/ui/forms-and-actions.public';
import { FolderTreePanel, UI_GRID_ROOMY_CLASSNAME } from '@/shared/ui/navigation-and-layout.public';
import {
  createMasterFolderTreeTransactionAdapter,
  FolderTreeViewportV2,
  useMasterFolderTreeShell,
  type FolderTreeViewportRenderNodeInput,
} from '@/shared/lib/foldertree/public';
import { SelectedNodeEditor } from './components/SelectedNodeEditor';
import { LibraryItemsList } from './components/LibraryItemsList';
import { LayoutNode } from './components/LayoutNode';

const TREE_INSTANCE = 'admin_menu_layout';

export function MenuBuilderSection(): React.JSX.Element {
  const {
    customEnabled,
    setCustomEnabled,
    layoutMasterNodes,
    replaceCustomNavFromMasterNodes,
    handleAddRootNode,
    addCustomChildNode,
    removeCustomNodeById,
    updateCustomNodeLabelById,
    updateCustomNodeSemanticById,
    updateCustomNodeHrefById,
    layoutNodeStateById,
    libraryQuery,
    setLibraryQuery,
    filteredLibraryItems,
    customIds,
    addBuiltInNode,
    handleReset,
  } = useAdminMenuSettings();

  const replaceCustomNavFromMasterNodesRef = useRef(replaceCustomNavFromMasterNodes);
  useEffect(() => {
    replaceCustomNavFromMasterNodesRef.current = replaceCustomNavFromMasterNodes;
  }, [replaceCustomNavFromMasterNodes]);

  const adapter = useMemo(
    () =>
      createMasterFolderTreeTransactionAdapter({
        onApply: (tx) => {
          replaceCustomNavFromMasterNodesRef.current(tx.nextNodes);
        },
      }),
    []
  );

  const {
    appearance: { rootDropUi },
    controller,
    viewport: { scrollToNodeRef },
  } = useMasterFolderTreeShell({
    instance: TREE_INSTANCE,
    nodes: layoutMasterNodes,
    adapter,
  });

  const selectedNodeId = controller.selectedNodeId;
  const selectedNode =
    selectedNodeId !== null && selectedNodeId !== ''
      ? (layoutNodeStateById.get(selectedNodeId) ?? null)
      : null;
  const selectedNodeSemantic = selectedNode?.semantic ?? 'group';

  const handleAddRoot = useCallback(
    (kind: 'link' | 'group'): void => {
      const nodeId = handleAddRootNode(kind);
      controller.selectNode(nodeId);
      controller.expandToNode?.(nodeId);
      controller.scrollToNode?.(nodeId);
    },
    [controller, handleAddRootNode]
  );

  const handleAddChild = useCallback(
    (kind: 'link' | 'group'): void => {
      if (selectedNodeId === null || selectedNodeId === '') return;
      const nodeId = addCustomChildNode(selectedNodeId, kind);
      if (nodeId === null || nodeId === '') return;
      controller.expandNode(selectedNodeId);
      controller.selectNode(nodeId);
      controller.expandToNode?.(nodeId);
      controller.scrollToNode?.(nodeId);
    },
    [addCustomChildNode, controller, selectedNodeId]
  );

  const renderLayoutNode = useCallback(
    (input: FolderTreeViewportRenderNodeInput): React.ReactNode => (
      <LayoutNode input={input} layoutNodeStateById={layoutNodeStateById} />
    ),
    [layoutNodeStateById]
  );

  const isSelectedNodeValid = selectedNodeId !== null && selectedNodeId !== '' && selectedNode !== null;

  return (
    <FormSection
      title='Menu Builder'
      description='Manage menu hierarchy with the Master folder tree runtime.'
      className='mt-6 p-6'
      variant='subtle'
    >
      <ToggleRow
        variant='switch'
        label='Use custom layout'
        description='Enable this to apply the custom menu structure defined below.'
        checked={customEnabled}
        onCheckedChange={setCustomEnabled}
        className='mb-6'
      />

      {customEnabled === false ? (
        <div className='mb-4 rounded-md border border-border/60 bg-card/40 px-3 py-2 text-xs text-gray-400'>
          Custom layout is disabled. Enable it to apply this menu structure.
        </div>
      ) : null}

      <div className='flex flex-wrap items-center gap-2'>
        <Button type='button' size='sm' onClick={() => handleAddRoot('link')}>
          <Plus className='mr-2 size-4' />
          Add root link
        </Button>
        <Button type='button' variant='outline' size='sm' onClick={() => handleAddRoot('group')}>
          <FolderPlus className='mr-2 size-4' />
          Add root group
        </Button>
        <Button
          type='button'
          variant='outline'
          size='sm'
          disabled={selectedNodeId === null || selectedNodeId === ''}
          onClick={() => handleAddChild('link')}
        >
          <Link2 className='mr-2 size-4' />
          Add child link
        </Button>
        <Button
          type='button'
          variant='outline'
          size='sm'
          disabled={selectedNodeId === null || selectedNodeId === ''}
          onClick={() => handleAddChild('group')}
        >
          <FolderPlus className='mr-2 size-4' />
          Add child group
        </Button>
        <Button
          type='button'
          variant='outline'
          size='sm'
          disabled={selectedNodeId === null || selectedNodeId === ''}
          onClick={() => {
            if (selectedNodeId === null || selectedNodeId === '') return;
            removeCustomNodeById(selectedNodeId);
            controller.selectNode(null);
          }}
        >
          <Trash2 className='mr-2 size-4' />
          Remove selected
        </Button>
        <Button
          type='button'
          variant='outline'
          size='sm'
          disabled={selectedNodeId === null || selectedNodeId === ''}
          onClick={() => {
            if (selectedNodeId === null || selectedNodeId === '') return;
            controller.dropNodeToRoot(selectedNodeId).catch(() => {});
          }}
        >
          <ArrowDownToLine className='mr-2 size-4' />
          Move selected to root
        </Button>
        <Button type='button' variant='outline' size='sm' onClick={() => handleReset()}>
          Restore default layout
        </Button>
      </div>

      <div className={`${UI_GRID_ROOMY_CLASSNAME} mt-6 lg:grid-cols-[minmax(0,1fr)_360px]`}>
        <div className='space-y-4'>
          <div>
            <h3 className='text-xs font-semibold uppercase tracking-wide text-gray-400'>Layout</h3>
            <p className='mt-1 text-[11px] text-gray-500'>
              Drag and drop nodes to reorder or nest them. Built-in items are read-only.
            </p>
          </div>

          <FolderTreePanel
            masterInstance={TREE_INSTANCE}
            className='h-[340px] rounded-md border border-border/60 bg-card/30 p-2'
          >
            <FolderTreeViewportV2
              controller={controller}
              scrollToNodeRef={scrollToNodeRef}
              rootDropUi={rootDropUi}
              renderNode={renderLayoutNode}
              emptyLabel='No menu items yet. Add links or groups to start building your menu.'
            />
          </FolderTreePanel>

          {isSelectedNodeValid ? (
            <SelectedNodeEditor
              selectedNodeId={selectedNodeId}
              selectedNode={selectedNode}
              selectedNodeSemantic={selectedNodeSemantic}
              updateCustomNodeLabelById={updateCustomNodeLabelById}
              updateCustomNodeSemanticById={updateCustomNodeSemanticById}
              updateCustomNodeHrefById={updateCustomNodeHrefById}
            />
          ) : null}
        </div>

        <LibraryItemsList
          libraryQuery={libraryQuery}
          setLibraryQuery={setLibraryQuery}
          filteredLibraryItems={filteredLibraryItems}
          customIds={customIds}
          onAdd={addBuiltInNode}
        />
      </div>
    </FormSection>
  );
}

'use client';

import React from 'react';
import { ChevronDown, ChevronRight } from 'lucide-react';
import { StatusBadge } from '@/shared/ui/data-display.public';
import { type FolderTreeViewportRenderNodeInput } from '@/shared/lib/foldertree/public';
import { cn } from '@/shared/utils/ui-utils';
import type { 
  AdminMenuLayoutNodeEntry, 
  AdminMenuLayoutNodeSemantic 
} from '../admin-menu-layout-types';

interface LayoutNodeProps {
  input: FolderTreeViewportRenderNodeInput;
  layoutNodeStateById: Map<string, AdminMenuLayoutNodeEntry>;
}

export function LayoutNode({
  input,
  layoutNodeStateById,
}: LayoutNodeProps): React.JSX.Element {
  const nodeState = layoutNodeStateById.get(input.node.id);
  const semantic: AdminMenuLayoutNodeSemantic = nodeState?.semantic ?? 'group';
  const isBuiltIn = nodeState?.isBuiltIn ?? false;

  const stateClassName = input.isSelected
    ? 'bg-blue-600/30 text-white ring-1 ring-blue-400/40'
    : input.dropPosition === 'before'
      ? 'bg-blue-500/10 text-gray-100 ring-1 ring-blue-500/40'
      : input.dropPosition === 'after'
        ? 'bg-cyan-500/10 text-gray-100 ring-1 ring-cyan-500/40'
        : 'text-gray-300 hover:bg-muted/40';

  return (
    <div
      className={cn(
        'group flex w-full items-center gap-2 rounded px-2 py-1.5 text-xs transition',
        stateClassName,
        input.isDragging && 'opacity-50'
      )}
      style={{ paddingLeft: `${input.depth * 16 + 8}px` }}
    >
      {input.hasChildren ? (
        <button
          type='button'
          className='inline-flex size-4 items-center justify-center rounded hover:bg-muted/50'
          onClick={(event: React.MouseEvent<HTMLButtonElement>): void => {
            event.preventDefault();
            event.stopPropagation();
            input.toggleExpand();
          }}
          aria-label={input.isExpanded ? 'Collapse node' : 'Expand node'}
          aria-expanded={input.isExpanded}
          title={input.isExpanded ? 'Collapse node' : 'Expand node'}
        >
          {input.isExpanded ? (
            <ChevronDown className='size-3.5 text-gray-400' />
          ) : (
            <ChevronRight className='size-3.5 text-gray-400' />
          )}
        </button>
      ) : (
        <span className='inline-flex size-4 items-center justify-center text-gray-500'>•</span>
      )}

      <button
        type='button'
        onClick={input.select}
        aria-pressed={input.isSelected}
        aria-label={input.node.name}
        className='flex min-w-0 flex-1 items-center gap-2 rounded-sm text-left focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-sky-400/70 focus-visible:ring-offset-2 focus-visible:ring-offset-slate-950'
      >
        <span className='min-w-0 flex-1 truncate'>{input.node.name}</span>

        <StatusBadge
          status={semantic === 'link' ? 'Link' : 'Group'}
          variant='info'
          size='sm'
          className='font-bold'
        />
        <StatusBadge
          status={isBuiltIn === true ? 'Built-in' : 'Custom'}
          variant={isBuiltIn === true ? 'warning' : 'success'}
          size='sm'
          className='font-bold'
        />
      </button>
    </div>
  );
}

'use client';

import React from 'react';
import { Button } from '@/shared/ui/primitives.public';
import { SearchInput } from '@/shared/ui/forms-and-actions.public';
import { SectionHeader, insetPanelVariants } from '@/shared/ui/navigation-and-layout.public';
import type { AdminNavNodeEntry } from '@/shared/contracts/admin';

interface LibraryItemsListProps {
  libraryQuery: string;
  setLibraryQuery: (q: string) => void;
  filteredLibraryItems: AdminNavNodeEntry[];
  customIds: Set<string>;
  onAdd: (entry: AdminNavNodeEntry) => void;
}

export function LibraryItemsList({
  libraryQuery,
  setLibraryQuery,
  filteredLibraryItems,
  customIds,
  onAdd,
}: LibraryItemsListProps): React.JSX.Element {
  return (
    <div>
      <h3 className='text-xs font-semibold uppercase tracking-wide text-gray-400'>
        Add built-in items
      </h3>
      <SearchInput
        value={libraryQuery}
        onChange={(event: React.ChangeEvent<HTMLInputElement>) =>
          setLibraryQuery(event.target.value)
        }
        placeholder='Search built-in menu…'
        className='mt-2 h-9 bg-gray-900/40'
        onClear={() => setLibraryQuery('')}
        size='sm'
      />
      <div className='mt-3 max-h-80 space-y-2 overflow-auto pr-2'>
        {filteredLibraryItems.length === 0 ? (
          <p
            className={`${insetPanelVariants({ radius: 'compact', padding: 'sm' })} border-border text-xs text-gray-400`}
          >
            No matching menu items.
          </p>
        ) : (
          filteredLibraryItems.map((entry: AdminNavNodeEntry) => {
            const isAdded = customIds.has(entry.id);
            return (
              <div
                key={entry.id}
                className='flex items-center justify-between gap-2 rounded-md border border-border/60 bg-card/30 p-3'
              >
                <SectionHeader
                  title={entry.label}
                  subtitle={`${entry.parents.join(' / ')}${entry.parents.length > 0 ? ' / ' : ''}${entry.href ?? 'Group'}`}
                  size='xs'
                  className='flex-1'
                  actions={
                    <Button
                      type='button'
                      variant='outline'
                      size='sm'
                      className='h-7 px-2 text-[11px]'
                      disabled={isAdded}
                      onClick={() => onAdd(entry)}
                    >
                      {isAdded ? 'Added' : 'Add'}
                    </Button>
                  }
                />
              </div>
            );
          })
        )}
      </div>
    </div>
  );
}

'use client';

import React from 'react';
import { Input } from '@/shared/ui/primitives.public';
import { FormSection, FormField, SelectSimple } from '@/shared/ui/forms-and-actions.public';
import { StatusBadge } from '@/shared/ui/data-display.public';
import type { LabeledOptionDto } from '@/shared/contracts/base';
import type { 
  AdminMenuLayoutNodeEntry, 
  AdminMenuLayoutNodeSemantic 
} from '../admin-menu-layout-types';

const NODE_TYPE_OPTIONS: Array<LabeledOptionDto<AdminMenuLayoutNodeSemantic>> = [
  { value: 'group', label: 'Group' },
  { value: 'link', label: 'Link' },
];

interface SelectedNodeEditorProps {
  selectedNodeId: string;
  selectedNode: AdminMenuLayoutNodeEntry;
  selectedNodeSemantic: AdminMenuLayoutNodeSemantic;
  updateCustomNodeLabelById: (id: string, val: string) => void;
  updateCustomNodeSemanticById: (id: string, val: AdminMenuLayoutNodeSemantic) => void;
  updateCustomNodeHrefById: (id: string, val: string) => void;
}

export function SelectedNodeEditor({
  selectedNodeId,
  selectedNode,
  selectedNodeSemantic,
  updateCustomNodeLabelById,
  updateCustomNodeSemanticById,
  updateCustomNodeHrefById,
}: SelectedNodeEditorProps): React.JSX.Element {
  return (
    <FormSection
      title='Selected Item'
      description='Edit properties for the currently selected menu node.'
      variant='subtle'
      className='p-4'
      actions={
        <StatusBadge
          status={selectedNode.isBuiltIn === true ? 'Built-in' : 'Custom'}
          variant={selectedNode.isBuiltIn === true ? 'warning' : 'success'}
          size='sm'
          className='font-bold'
        />
      }
    >
      <div className='grid gap-3 md:grid-cols-2'>
        <FormField label='Label'>
          <Input
            value={selectedNode.label}
            onChange={(event: React.ChangeEvent<HTMLInputElement>) =>
              updateCustomNodeLabelById(selectedNodeId, event.target.value)
            }
            className='h-8 bg-gray-900/40 text-xs'
            disabled={selectedNode.isBuiltIn === true}
            aria-label='Label'
            title='Label'
          />
        </FormField>

        <FormField label='Type'>
          <SelectSimple
            size='sm'
            value={selectedNodeSemantic}
            options={NODE_TYPE_OPTIONS}
            onValueChange={(value: string) =>
              updateCustomNodeSemanticById(
                selectedNodeId,
                value === 'link' ? 'link' : 'group'
              )
            }
            disabled={selectedNode.isBuiltIn === true}
            triggerClassName='h-8 text-xs'
            ariaLabel='Type'
            title='Type'
          />
        </FormField>
      </div>

      {selectedNodeSemantic === 'link' ? (
        <FormField label='Href' className='mt-3'>
          <Input
            value={selectedNode.href ?? ''}
            onChange={(event: React.ChangeEvent<HTMLInputElement>) =>
              updateCustomNodeHrefById(selectedNodeId, event.target.value)
            }
            placeholder='/admin/...'
            className='h-8 bg-gray-900/40 text-xs'
            disabled={selectedNode.isBuiltIn === true}
            aria-label='/admin/...'
            title='/admin/...'
          />
        </FormField>
      ) : null}

      {selectedNode.isBuiltIn === true ? (
        <p className='mt-3 text-[11px] text-amber-200/80'>
          Built-in node metadata is locked. You can still move or remove this node from the
          custom layout.
        </p>
      ) : null}
    </FormSection>
  );
}

'use client';

import { ArrowLeft, Plus, Save } from 'lucide-react';
import Link from 'next/link';
import React from 'react';

import { Badge, Button, Input } from '@/shared/ui/primitives.public';
import { AdminSectionBreadcrumbs } from '@/shared/ui/admin.public';
import { AdminTitleBreadcrumbHeader } from '@/shared/ui/admin-title-breadcrumb-header';
import { FormSection, SelectSimple } from '@/shared/ui/forms-and-actions.public';

import {
  VALIDATOR_LISTS_VIEW_LABELS,
  scopeOptions,
  type ValidatorListsView,
} from './types';
import { getViewContentId, getViewTriggerId } from './utils';

export function ValidatorListsHeader({
  activeView,
  isDirty,
  isPending,
  listsCount,
  totalLocked,
  onSave,
}: {
  activeView: ValidatorListsView;
  isDirty: boolean;
  isPending: boolean;
  listsCount: number;
  totalLocked: number;
  onSave: () => void;
}) {
  return (
    <AdminTitleBreadcrumbHeader
      title={
        <h1 className='text-3xl font-bold tracking-tight text-white'>
          Validation Pattern Lists
        </h1>
      }
      breadcrumb={
        <AdminSectionBreadcrumbs
          section={{ label: 'Global Validator', href: '/admin/validator' }}
          current={activeView === 'tooltips' ? 'Settings' : 'Validation Pattern Lists'}
          data-testid='validator-lists-breadcrumbs'
        />
      }
      actions={
        <>
          <Button type='button' variant='outline' size='xs' asChild>
            <Link href='/admin/validator'>
              <ArrowLeft className='mr-2 size-4' />
              Back To Validator
            </Link>
          </Button>
          <Button
            type='button'
            size='xs'
            onClick={onSave}
            disabled={!isDirty || isPending}
          >
            <Save className='mr-2 size-4' />
            Save Lists
          </Button>
          <Badge variant='outline' className='border-white/10 text-gray-300'>
            {listsCount} lists
          </Badge>
          <Badge variant='outline' className='border-white/10 text-gray-300'>
            {totalLocked} locked
          </Badge>
        </>
      }
    />
  );
}

